package github.chains;

import spoon.Launcher;
import spoon.reflect.code.*;
import spoon.reflect.declaration.*;
import spoon.reflect.factory.Factory;
import spoon.reflect.reference.CtExecutableReference;
import spoon.reflect.reference.CtTypeReference;
import spoon.reflect.visitor.filter.TypeFilter;

import java.util.List;

public class Main {
    public static void main(String[] args) {
        // Create a Spoon launcher
        Launcher launcher = new Launcher();

        // Set the source directory to the lithium project
        launcher.addInputResource("/workspace/lithium/src");

        // Set the output directory
        launcher.setSourceOutputDirectory("/workspace/spoon-output");

        // Build the model
        launcher.buildModel();

        // Get the factory
        Factory factory = launcher.getFactory();

        // Find all DropwizardApacheConnector constructor calls
        // This pattern matches the old constructor with 2 parameters
        List<CtNewClass> newClasses = launcher.getFactory().Query().select(new TypeFilter<CtNewClass>(CtNewClass.class) {
            @Override
            public boolean matches(CtNewClass element) {
                if (element.getAnonymousClass() != null) {
                    // Check if it's DropwizardApacheConnector
                    CtTypeReference<?> typeRef = element.getAnonymousClass().getSuperclass();
                    if (typeRef != null && typeRef.getQualifiedName().contains("DropwizardApacheConnector")) {
                        return true;
                    }
                }
                return false;
            }
        });

        // Find constructor calls with DropwizardApacheConnector
        List<CtConstructorCall<?>> constructorCalls = launcher.getFactory().Query().select(new TypeFilter<CtConstructorCall<?>>(CtConstructorCall.class) {
            @Override
            public boolean matches(CtConstructorCall<?> element) {
                return element.getType().getQualifiedName().contains("DropwizardApacheConnector");
            }
        });

        // Fix the constructor calls by adding the boolean parameter
        for (CtConstructorCall<?> call : constructorCalls) {
            // Get the constructor reference
            CtExecutableReference<?> constructorRef = call.getExecutable();

            // Check if we're calling the old constructor (2 parameters) vs new one (3 parameters)
            if (call.getArguments().size() == 2) {
                // Add the boolean parameter with default value false
                call.addArgument(factory.createLiteral(false));
            }
        }

        // Generate the fixed code
        launcher.export();

        System.out.println("Transformation completed for Dropwizard client 4.0.0 compatibility");
    }
}

